class Playground {
    async run(inputs) {
        const arr = JSON.parse(inputs[0]);
        const target = parseInt(inputs[1]);

        // 1. Initialize data structures
        await this.nums.init(arr);
        await this.vars.init([
            ["left", 0],
            ["right", arr.length - 1],
            ["target", target]
        ]);

        let left = 0;
        let right = arr.length - 1;

        this.log(`Starting Binary Search for target: ${target}`);
        await this.await();

        while (left <= right) {
            // Calculate mid
            const mid = Math.floor((left + right) / 2);
            const midVal = this.nums.get(mid);

            // Update Visualizer State
            this.vars.put("left", left);
            this.vars.put("right", right);
            this.vars.put("mid", mid);

            // Highlight the current search range and the mid point
            // Clear previous highlights first (using null or reset logic)
            for(let i=0; i<arr.length; i++) this.nums.highlight(i, null);

            this.nums.highlightRange(left, right, "#e0f7fa"); // Light blue search area
            this.nums.highlight(mid, "#ffb703"); // Amber for the pivot/mid

            this.log(`Checking mid index ${mid} (Value: ${midVal})`);
            await this.await();

            if (midVal === target) {
                this.nums.highlight(mid, "#00f5a0"); // Success green
                this.log(`Found target ${target} at index ${mid}!`);
                await this.await();
                return mid;
            }

            if (midVal < target) {
                this.log(`${midVal} < ${target}, discarding the left half.`);
                left = mid + 1;
            } else {
                this.log(`${midVal} > ${target}, discarding the right half.`);
                right = mid - 1;
            }

            this.vars.put("left", left);
            this.vars.put("right", right);
            await this.await();
        }

        this.log("Target not found in the array.");
        await this.await();
        return -1;
    }
}
